from itertools import combinations
class Solution:
    def maxWeight(self, pizzas):
        n = len(pizzas)
        pizzas = tuple(pizzas)
        full_mask = (1 << n) - 1
        memo = {}

        def solve(mask):
            if mask == 0:
                return 0
            if mask in memo:
                return memo[mask]
            remaining = bin(mask).count('1')
            used = n - remaining
            day = used // 4 + 1
            indices = [i for i in range(n) if mask & (1 << i)]
            best = float('-inf')
            for combo in combinations(indices, 4):
                vals = sorted(pizzas[i] for i in combo)
                gain = vals[3] if day % 2 == 1 else vals[2]
                new_mask = mask
                for i in combo:
                    new_mask &= ~(1 << i)
                cand = gain + solve(new_mask)
                if cand > best:
                    best = cand
            memo[mask] = best
            return best

        return solve(full_mask)

