var maxWeight = function(pizzas) {
    const n = pizzas.length;
    const arr = [...pizzas].sort((a, b) => b - a);
    const numDays = Math.floor(n / 4);
    const oddDays = Math.ceil(numDays / 2);
    const evenDays = Math.floor(numDays / 2);
    let total = 0;
    for (let i = 0; i < oddDays; i++) total += arr[i];
    for (let i = 0; i < evenDays; i++) total += arr[oddDays + 2 * i + 1];
    return total;
};
